BrandingOptions.CustomCss:
/* S7 SkyQUBi — Jellyfin theme overlay */
:root {
  --s7-purple: #2b1b4e;
  --s7-purple-deep: #1a0f33;
  --s7-sunset: #d97a3e;
  --s7-gold: #d4af37;
  --s7-cream: #f4e8d8;
}

.skinHeader,
.skinHeader-withBackground {
  background: linear-gradient(180deg, var(--s7-purple) 0%, var(--s7-purple-deep) 100%) !important;
  border-bottom: 1px solid var(--s7-gold) !important;
}

.mainDrawer,
.navMenuOption {
  background-color: var(--s7-purple-deep) !important;
}

.navMenuOption-selected {
  background-color: var(--s7-purple) !important;
  border-left: 3px solid var(--s7-gold) !important;
}

.button-submit,
.raised.button-submit {
  background-color: var(--s7-sunset) !important;
  color: #fff !important;
}

a,
.emby-button-foreground-accent,
.headerTabs .emby-tab-button-active {
  color: var(--s7-gold) !important;
}

.headerTabs .emby-tab-button-active {
  border-bottom-color: var(--s7-gold) !important;
}

.cardOverlayButton-br {
  background-color: rgba(43, 27, 78, 0.85) !important;
}

.disclaimerContainer {
  color: var(--s7-cream) !important;
  font-style: italic;
  text-align: center;
  padding: 0.6em 0;
  border-top: 1px solid var(--s7-gold);
}
